class SensitiveFieldEncryptor(private val encryptionManager: EncryptionManager = EncryptionManager.getInstance()) {

    fun encryptCreditCard(cardNumber: String): String {
        val sanitized = cardNumber.replace("\\s|-".toRegex(), "")
        require(sanitized.matches(Regex("^\\d{13,19}$"))) {
            "Invalid credit card number format"
        }
        return encryptionManager.encrypt(sanitized)
    }

    fun decryptCreditCard(encryptedCard: String): String {
        return encryptionManager.decrypt(encryptedCard)
    }

    fun encryptSSN(ssn: String): String {
        val sanitized = ssn.replace("-", "")
        require(sanitized.matches(Regex("^\\d{9}$"))) {
            "Invalid SSN format"
        }
        return encryptionManager.encrypt(sanitized)
    }

    fun decryptSSN(encryptedSSN: String): String {
        return encryptionManager.decrypt(encryptedSSN)
    }

    fun encryptAuthToken(token: String): String {
        require(token.isNotBlank()) { "Auth token must not be blank" }
        return encryptionManager.encrypt(token)
    }

    fun decryptAuthToken(encryptedToken: String): String {
        return encryptionManager.decrypt(encryptedToken)
    }

    /**
